#include <iostream>
#include <string>
#include <vector>
#include <cmath>

// Function to generate a sequence of numbers
std::vector<int> generateSequence(int start, int end, int step) {
    std::vector<int> sequence;
    for (int i = start; i <= end; i += step) {
        sequence.push_back(i);
    }
    return sequence;
}

// Function to create a pattern with numbers and characters
std::string createPattern(std::vector<int> sequence) {
    std::string result;
    int length = sequence.size();

    for (int i = 0; i < length; ++i) {
        result += std::to_string(sequence[i]);
        if (i < length - 1) {
            result += " ";
        }
    }

    return result;
}

// Function to create a complex pattern with numbers and characters
std::string complexPattern(int rows, int cols, int start, int end, int step) {
    std::string pattern;

    for (int i = 0; i < rows; ++i) {
        std::string row;
        for (int j = 0; j < cols; ++j) {
            // Add a number based on the sequence
            int num = start + i * step + j;
            row += std::to_string(num);

            // Add a character if the number is a multiple of 3
            if (num % 3 == 0) {
                row += 'j';
            }
        }
        pattern += row + "\n";
    }

    return pattern;
}

// Main function
int main() {
    int rows = 5;
    int cols = 5;
    int start = 1;
    int end = 15;
    int step = 3;

